class Solution {
    public int countLargestGroup(int n) {
        int[] groupCounts = new int[37]; // Max digit sum for n=10^4 is 36 (9999)
        for (int i = 1; i <= n; i++) {
            int sum = 0;
            int num = i;
            while (num > 0) {
                sum += num % 10;
                num /= 10;
            }
            groupCounts[sum]++;
        }
        int maxCount = 0;
        for (int count : groupCounts) {
            if (count > maxCount) {
                maxCount = count;
            }
        }
        int result = 0;
        for (int count : groupCounts) {
            if (count == maxCount) {
                result++;
            }
        }
        return result;
    }
}

